	@Test
	public void repeatedSinglePatternExistsProbeUsesCachedIdResult(@TempDir java.nio.file.Path tempDir)
			throws IOException {
		LmdbStore store = new LmdbStore(tempDir.toFile());
		SailRepository repository = new SailRepository(store);
		repository.init();

		ValueFactory vf = SimpleValueFactory.getInstance();
		IRI alice = vf.createIRI(NS, "single-exists-alice");
		IRI likes = vf.createIRI(NS, "single-exists-likes");
		IRI pizza = vf.createIRI(NS, "single-exists-pizza");

		try (RepositoryConnection conn = repository.getConnection()) {
			conn.add(alice, likes, pizza);
		}

		StatementPattern pattern = new StatementPattern(new Var("person"), new Var("p", likes), new Var("item"));

		SailSource branch = store.getBackingStore().getExplicitSailSource();
		SailDataset dataset = branch.dataset(IsolationLevels.READ_COMMITTED);

		try {
			LmdbEvaluationDataset lmdbDataset = (LmdbEvaluationDataset) dataset;
			RecordingDataset recordingDataset = new RecordingDataset(lmdbDataset);

			SailDatasetTripleSource tripleSource = new SailDatasetTripleSource(repository.getValueFactory(), dataset);
			QueryEvaluationContext ctx = new LmdbQueryEvaluationContext(null, tripleSource.getValueFactory(),
					tripleSource.getComparator(), recordingDataset, lmdbDataset.getValueStore());

			assertThat(lmdbDataset.hasTransactionChanges()).isFalse();
			assertThat(LmdbEvaluationStrategy.hasActiveConnectionChanges()).isFalse();
			assertThat(LmdbEvaluationStrategy.idJoinsAllowedForIsolation(lmdbDataset.getIsolationLevel())).isTrue();
			long aliceId = lmdbDataset.getValueStore().getId(alice);
			long likesId = lmdbDataset.getValueStore().getId(likes);
			assertThat(aliceId).isNotEqualTo(LmdbValue.UNKNOWN_ID);
			assertThat(likesId).isNotEqualTo(LmdbValue.UNKNOWN_ID);
			String index = lmdbDataset.selectBestIndex(aliceId, likesId, LmdbValue.UNKNOWN_ID, LmdbValue.UNKNOWN_ID);
			assertThat(index).isNotNull();
			RecordIterator direct = recordingDataset.getRecordIterator(index, aliceId, likesId, LmdbValue.UNKNOWN_ID,
					LmdbValue.UNKNOWN_ID, KeyRangeBuffers.acquire(), new long[4], null);
			try {
				assertThat(direct.next()).isNotNull();
			} finally {
				direct.close();
			}

			LmdbIdStatementPatternExistsQueryValueEvaluationStep step = new LmdbIdStatementPatternExistsQueryValueEvaluationStep(
					pattern, (LmdbDatasetContext) ctx,
					ignored -> QueryEvaluationStep.EMPTY_ITERATION);
			MapBindingSet bindings = new MapBindingSet(1);
			bindings.addBinding("person", alice);

			assertThat(step.evaluate(bindings)).isEqualTo(BooleanLiteral.TRUE);
			int callsAfterFirstProbe = recordingDataset.rawApiCallCount();

			assertThat(step.evaluate(bindings)).isEqualTo(BooleanLiteral.TRUE);

			assertThat(recordingDataset.rawApiCallCount()).isEqualTo(callsAfterFirstProbe);
		} finally {
			dataset.close();
			branch.close();
			repository.shutDown();
		}
	}

	@Test
	public void repeatedSinglePatternExistsRecordsEvalDpProbeTelemetryWhenEnabled(
			@TempDir java.nio.file.Path tempDir) throws IOException {
		String previousEvalDp = System.getProperty(LmdbEvalDpClassifier.ENABLED_PROPERTY);
		System.setProperty(LmdbEvalDpClassifier.ENABLED_PROPERTY, "true");
		LmdbStore store = new LmdbStore(tempDir.toFile());
		SailRepository repository = new SailRepository(store);
		repository.init();

		ValueFactory vf = SimpleValueFactory.getInstance();
		IRI alice = vf.createIRI(NS, "single-exists-evaldp-alice");
		IRI likes = vf.createIRI(NS, "single-exists-evaldp-likes");
		IRI pizza = vf.createIRI(NS, "single-exists-evaldp-pizza");

		try (RepositoryConnection conn = repository.getConnection()) {
			conn.add(alice, likes, pizza);
		}

		StatementPattern pattern = new StatementPattern(new Var("person"), new Var("p", likes), new Var("item"));
		pattern.setRuntimeTelemetryEnabled(true);

		SailSource branch = store.getBackingStore().getExplicitSailSource();
		SailDataset dataset = branch.dataset(IsolationLevels.READ_COMMITTED);

		try {
			LmdbEvaluationDataset lmdbDataset = (LmdbEvaluationDataset) dataset;
			SailDatasetTripleSource tripleSource = new SailDatasetTripleSource(repository.getValueFactory(), dataset);
			QueryEvaluationContext ctx = new LmdbQueryEvaluationContext(null, tripleSource.getValueFactory(),
					tripleSource.getComparator(), lmdbDataset, lmdbDataset.getValueStore());

			LmdbIdStatementPatternExistsQueryValueEvaluationStep step = new LmdbIdStatementPatternExistsQueryValueEvaluationStep(
					pattern, (LmdbDatasetContext) ctx,
					ignored -> QueryEvaluationStep.EMPTY_ITERATION);
			MapBindingSet bindings = new MapBindingSet(1);
			bindings.addBinding("person", alice);

			assertThat(step.evaluate(bindings)).isEqualTo(BooleanLiteral.TRUE);
			assertThat(step.evaluate(bindings)).isEqualTo(BooleanLiteral.TRUE);

			assertThat(pattern.getStringMetricPlanned("lmdbEvalDpMode")).isEqualTo("probe-dp");
			assertThat(pattern.getStringMetricActual("lmdbEvalDpModeActual")).isEqualTo("probe-dp");
			assertThat(pattern.getStringMetricPlanned("lmdbEvalDpShape"))
					.startsWith("lmdb-plan-shape:statement-pattern-exists:");
			assertThat(pattern.getLongMetricActual("lmdbEvalDpProbeLookupsActual")).isEqualTo(2);
			assertThat(pattern.getLongMetricActual("lmdbEvalDpProbeExecutionsActual")).isEqualTo(1);
			assertThat(pattern.getLongMetricActual("lmdbEvalDpProbeCacheHitsActual")).isEqualTo(1);
		} finally {
			if (previousEvalDp == null) {
				System.clearProperty(LmdbEvalDpClassifier.ENABLED_PROPERTY);
			} else {
				System.setProperty(LmdbEvalDpClassifier.ENABLED_PROPERTY, previousEvalDp);
			}
			dataset.close();
			branch.close();
			repository.shutDown();
		}
	}

	@Test
	public void singlePatternExistsUsesComponentScanForAnyRowProbe(@TempDir java.nio.file.Path tempDir)
			throws IOException {
		LmdbStore store = new LmdbStore(tempDir.toFile());
		store.setDefaultIsolationLevel(IsolationLevels.READ_COMMITTED);
		SailRepository repository = new SailRepository(store);
		repository.init();

		ValueFactory vf = SimpleValueFactory.getInstance();
		IRI alice = vf.createIRI(NS, "single-any-exists-alice");
		IRI likes = vf.createIRI(NS, "single-any-exists-likes");
		IRI pizza = vf.createIRI(NS, "single-any-exists-pizza");

		try (RepositoryConnection conn = repository.getConnection()) {
			conn.add(alice, likes, pizza);
		}

		StatementPattern pattern = new StatementPattern(new Var("person"), new Var("p", likes),
				new Var("item", pizza));

		SailSource branch = store.getBackingStore().getExplicitSailSource();
		SailDataset dataset = branch.dataset(IsolationLevels.READ_COMMITTED);

		try {
			LmdbEvaluationDataset lmdbDataset = (LmdbEvaluationDataset) dataset;
			RecordingDataset recordingDataset = new RecordingDataset(lmdbDataset);
			SailDatasetTripleSource tripleSource = new SailDatasetTripleSource(repository.getValueFactory(), dataset);
			QueryEvaluationContext ctx = new LmdbQueryEvaluationContext(null, tripleSource.getValueFactory(),
					tripleSource.getComparator(), recordingDataset, lmdbDataset.getValueStore());

			LmdbIdStatementPatternExistsQueryValueEvaluationStep step = new LmdbIdStatementPatternExistsQueryValueEvaluationStep(
					pattern, (LmdbDatasetContext) ctx,
					ignored -> QueryEvaluationStep.EMPTY_ITERATION);

			assertThat(step.evaluate(EmptyBindingSet.getInstance())).isEqualTo(BooleanLiteral.TRUE);
			assertThat(recordingDataset.componentScanCallCount())
					.as("any-row EXISTS should use an ID component scan instead of materializing quads")
					.isEqualTo(1);
			assertThat(recordingDataset.rawApiCallCount())
					.as("any-row EXISTS should not materialize raw records")
					.isZero();
		} finally {
			dataset.close();
			branch.close();
			repository.shutDown();
		}
	}

	@Test
	public void constantCodeDistinctCountUsesComponentScans(@TempDir java.nio.file.Path tempDir) throws Exception {
		LmdbStore store = LmdbTestUtil.newStoreWithLmdbEvaluationStrategy(tempDir.toFile());
		store.setDefaultIsolationLevel(IsolationLevels.READ_COMMITTED);
		SailRepository repository = new SailRepository(store);
		repository.init();

		ValueFactory vf = SimpleValueFactory.getInstance();
		IRI encounterType = vf.createIRI(NS, "constantCodeEncounterType");
		IRI codePredicate = vf.createIRI(NS, "constantCodeCodePredicate");
		IRI codeA = vf.createIRI(NS, "constantCodeA");
		IRI codeB = vf.createIRI(NS, "constantCodeB");
		IRI codeC = vf.createIRI(NS, "constantCodeC");
		IRI encounterA = vf.createIRI(NS, "constantCodeEncounterA");
		IRI encounterB = vf.createIRI(NS, "constantCodeEncounterB");
		IRI encounterC = vf.createIRI(NS, "constantCodeEncounterC");

		try (RepositoryConnection conn = repository.getConnection()) {
			conn.add(encounterA, RDF.TYPE, encounterType);
			conn.add(encounterA, codePredicate, codeA);
			conn.add(encounterB, RDF.TYPE, encounterType);
			conn.add(encounterB, codePredicate, codeB);
			conn.add(encounterC, RDF.TYPE, encounterType);
			conn.add(encounterC, codePredicate, codeC);
		}

		TupleExpr armA = codeArm(encounterType, codePredicate, codeA);
		TupleExpr armB = codeArm(encounterType, codePredicate, codeB);
		TupleExpr union = new Union(armA, armB);
		Group group = new Group(union);

		SailSource branch = store.getBackingStore().getExplicitSailSource();
		SailDataset dataset = branch.dataset(IsolationLevels.READ_COMMITTED);
		try {
			LmdbEvaluationDataset lmdbDataset = (LmdbEvaluationDataset) dataset;
			RecordingDataset recordingDataset = new RecordingDataset(lmdbDataset);
			SailDatasetTripleSource tripleSource = new SailDatasetTripleSource(repository.getValueFactory(), dataset);
			QueryEvaluationContext ctx = new LmdbQueryEvaluationContext(null, tripleSource.getValueFactory(),
					tripleSource.getComparator(), recordingDataset, lmdbDataset.getValueStore());
			QueryEvaluationStep fallback = ignored -> {
				MapBindingSet result = new MapBindingSet(1);
				result.addBinding("count", vf.createLiteral(99));
				return new SingletonIteration<>(result);
			};
			QueryEvaluationStep step = LmdbIdConstantCodeDistinctCountQueryEvaluationStep.tryCreate(group, union,
					"enc", "count", (LmdbDatasetContext) ctx, fallback, ctx, vf);
			assertThat(step).isNotNull();

			LmdbEvaluationStrategy.setCurrentDataset(recordingDataset);
			try (CloseableIteration<BindingSet> iter = step.evaluate(EmptyBindingSet.getInstance())) {
				assertThat(iter.hasNext()).isTrue();
				assertThat(iter.next().getValue("count").stringValue()).isEqualTo("2");
				assertThat(iter.hasNext()).isFalse();
			} finally {
				LmdbEvaluationStrategy.clearCurrentDataset();
			}

			assertThat(recordingDataset.componentScanCallCount())
					.as("constant-code distinct count should scan subject IDs directly")
					.isEqualTo(4);
			assertThat(recordingDataset.rawApiCallCount())
					.as("constant-code distinct count should not materialize quads")
					.isZero();
		} finally {
			dataset.close();
			branch.close();
			repository.shutDown();
		}
	}

	private static TupleExpr codeArm(IRI encounterType, IRI codePredicate, IRI code) {
		StatementPattern typePattern = new StatementPattern(new Var("enc"), new Var("type", RDF.TYPE),
				new Var("encounterType", encounterType));
		StatementPattern codePattern = new StatementPattern(new Var("enc"), new Var("codePredicate", codePredicate),
				new Var("code"));
		return new Filter(new Join(typePattern, codePattern),
				new Compare(new Var("code"), new ValueConstant(code), Compare.CompareOp.EQ));
	}

